const items = $input.all();

let parsed = [];
try {
  const raw = items[0].json;
  let jsonString = raw.text || raw.content || '';

  if (jsonString) {
    jsonString = jsonString
      .replace(/```(?:json)?\s*/g, '')
      .replace(/\s*```/g, '')
      .trim();
    parsed = JSON.parse(jsonString);
  } else if (raw.fullName || raw.name) {
    // format:json outputs fields directly instead of as a string
    parsed = [raw];
  } else {
    // Try parsing the entire output as JSON string
    const str = JSON.stringify(raw);
    parsed = JSON.parse(str);
  }
} catch(e) {
  console.log('Parse Fehler:', e.message);
  return [];
}

if (!Array.isArray(parsed)) {
  parsed = [parsed];
}

// Deep search helpers
function findInObj(obj, keys) {
  if (!obj || typeof obj !== 'object') return '';
  for (const key of keys) {
    if (obj[key] && typeof obj[key] === 'string') return obj[key];
  }
  for (const val of Object.values(obj)) {
    if (typeof val === 'object') {
      const found = findInObj(val, keys);
      if (found) return found;
    }
    if (Array.isArray(val)) {
      for (const item of val) {
        const found = findInObj(item, keys);
        if (found) return found;
      }
    }
  }
  return '';
}

function findEmail(obj) {
  const str = JSON.stringify(obj);
  const match = str.match(/"([^"]+@[^"]+\.[^"]+)"/);
  return match ? match[1] : '';
}

function findPhones(obj) {
  const str = JSON.stringify(obj);
  const matches = [...str.matchAll(/"(\+?(?:49|0)[\d\s\/()\-]{6,20})"/g)];
  return matches.map(m => m[1].trim());
}

function isMobile(phone) {
  const n = phone.replace(/[\s()\-\/]/g, '');
  return /^(\+49|0049|0)(15|16|17)/.test(n);
}

const contacts = parsed.map(obj => {
  const fullName = findInObj(obj, ['fullName', 'name', 'full_name']) ||
    (Array.isArray(obj.references) ? obj.references[0] : '') || '';
  const email = findInObj(obj, ['email', 'mail', 'e-mail']) || findEmail(obj);
  const validEmail = email.includes('@') ? email : '';

  const phones = findPhones(obj);
  let mobilePhone = findInObj(obj, ['mobilePhone', 'mobile', 'mobil', 'handy']) || '';
  let landlinePhone = findInObj(obj, ['landlinePhone', 'landline', 'phone', 'tel', 'telefon', 'festnetz', 'büro', 'office']) || '';

  if (!mobilePhone && !landlinePhone) {
    for (const p of phones) {
      if (isMobile(p) && !mobilePhone) mobilePhone = p;
      else if (!isMobile(p) && !landlinePhone) landlinePhone = p;
    }
  }

  return { fullName, mobilePhone, landlinePhone, email: validEmail };
});

return contacts.map(contact => ({
  json: {
    line: `${contact.fullName || ''}    ${contact.mobilePhone || ''}    ${contact.landlinePhone || ''}    ${contact.email || ''}`
  }
}));

const items = $input.all();
const plainText = items.map(item => item.json.line).join('\n');

return [{
  json: {
    text: plainText
  }
}];

const items = $input.all();
const existingContent = items[0].json.existingContent || '';
const newContactsText = items[0].json.text || '';

function normalizePhone(phone) {
  if (!phone) return '';
  return phone.replace(/[\s()\-\/]/g, '');
}

const newLines = newContactsText.split('\n').filter(l => l.trim());
const newContacts = newLines.map(line => {
  const parts = line.split(/    +/).map(p => p.trim());
  return {
    fullName: parts[0] || '',
    mobilePhone: normalizePhone(parts[1]),
    landlinePhone: normalizePhone(parts[2]),
    email: parts[3] || ''
  };
});

const companyKeywords = ['team', 'gmbh', 'recruiting', 'service', 'inc', 'ltd', ' ag', 'ug ', ' kg', 'ohg', 'gbr'];

function isCompanyContact(name) {
  const lower = name.toLowerCase();
  return companyKeywords.some(kw => lower.includes(kw));
}

const filtered = newContacts.filter(c => {
  if (!c.fullName) return false;
  const nameLower = c.fullName.toLowerCase();
  if (nameLower.includes('alexandrov') || nameLower === 'atanas alexandrov') return false;
  if (!c.mobilePhone && !c.landlinePhone) return false;
  if (isCompanyContact(c.fullName)) return false;
  return true;
});

function isDuplicate(contact) {
  const nameLower = contact.fullName.toLowerCase();
  return existingContent.toLowerCase().includes(nameLower);
}

const toAdd = filtered.filter(c => !isDuplicate(c));

if (toAdd.length === 0) {
  return [{ json: { text: existingContent } }];
}

function padRight(str, len) {
  if (!str) str = '';
  return str.length >= len ? str : str + ' '.repeat(len - str.length);
}

const newRows = toAdd.map(c => {
  const name = padRight(c.fullName, 30);
  const mobile = padRight(c.mobilePhone, 14);
  const landline = padRight(c.landlinePhone, 16);
  const email = padRight(c.email, 37);
  return `| ${name} | ${mobile} | ${landline} | ${email} |`;
});

const result = existingContent.trimEnd() + '\n' + newRows.join('\n');

return [{ json: { text: result } }];
